void cursorMenu(int x, int y) {
	Console::SetCursorPosition(x, y);
}
void coloresMenu(int n) {
	switch (n) {
	case 0:  Console::ForegroundColor = ConsoleColor::Black; break;
	case 1:  Console::ForegroundColor = ConsoleColor::Cyan; break;
	case 2:  Console::ForegroundColor = ConsoleColor::White; break;
	case 3:  Console::ForegroundColor = ConsoleColor::Yellow; break;
	case 4:  Console::ForegroundColor = ConsoleColor::Green; break;
	}
}
void dibujarFondoMenu() {
	for (int i = 0; i < PRESENTACION_ALTO; i++) {
		for (int c = 0; c < PRESENTACION_ANCHO; c++) {
			if (fondoMenu[i][c] == 0) coloresMenu(0);
			if (fondoMenu[i][c] == 1) coloresMenu(1);
			if (fondoMenu[i][c] == 2) coloresMenu(2);
			if (fondoMenu[i][c] == 3) coloresMenu(3);
			if (fondoMenu[i][c] == 4) coloresMenu(4);
			cursorMenu(c, i); cout << (char)219;
		}
	}
	Console::ForegroundColor = ConsoleColor::White;

}